     1→/**
     2→ * Field Editor Component
     3→ * Edit individual form field configuration
     4→ */
     5→
     6→import { useState, useEffect } from 'react';
     7→import type { FormField, FieldType } from '../../types/forms';
     8→import { X } from 'lucide-react';
     9→import { ConditionalRuleEditor } from './ConditionalRuleEditor';
    10→
    11→interface FieldEditorProps {
    12→  field: FormField | null;
    13→  allFields: FormField[]; // P0: All fields for conditional logic
    14→  onSave: (field: FormField) => void;
    15→  onCancel: () => void;
    16→}
    17→
    18→const FIELD_TYPES: { value: FieldType; label: string }[] = [
    19→  { value: 'text', label: 'Text' },
    20→  { value: 'textarea', label: 'Text Area' },
    21→  { value: 'number', label: 'Number' },
    22→  { value: 'date', label: 'Date' },
    23→  { value: 'time', label: 'Time' },
    24→  { value: 'select', label: 'Select (Dropdown)' },
    25→  { value: 'multiselect', label: 'Multi-Select' },
    26→  { value: 'radio', label: 'Radio Buttons' },
    27→  { value: 'checkbox', label: 'Checkbox' },
    28→  { value: 'rating', label: 'Rating (1-5)' },
    29→  { value: 'scale', label: 'Scale (1-10)' },
    30→  { value: 'file', label: 'File Upload' }, // P0: File upload field type
    31→];
    32→
    33→export function FieldEditor({ field, allFields, onSave, onCancel }: FieldEditorProps) {
    34→  const [formData, setFormData] = useState<FormField>(
    35→    field || {
    36→      id: crypto.randomUUID(),
    37→      type: 'text',
    38→      label: '',
    39→      description: '',
    40→      required: false,
    41→      order: 0,
    42→    }
    43→  );
    44→
    45→  const [optionsText, setOptionsText] = useState('');
    46→  const [showAdvancedOptions, setShowAdvancedOptions] = useState(false);
    47→
    48→  useEffect(() => {
    49→    if (field) {
    50→      setFormData(field);
    51→      if (field.options) {
    52→        setOptionsText(field.options.join('\n'));
    53→      }
    54→    }
    55→  }, [field]);
    56→
    57→  const needsOptions = ['select', 'multiselect', 'radio'].includes(formData.type);
    58→
    59→  const handleSubmit = (e: React.FormEvent) => {
    60→    e.preventDefault();
    61→
    62→    if (!formData.label.trim()) {
    63→      alert('Field label is required');
    64→      return;
    65→    }
    66→
    67→    if (needsOptions && !optionsText.trim()) {
    68→      alert('Options are required for this field type');
    69→      return;
    70→    }
    71→
    72→    const finalField: FormField = {
    73→      ...formData,
    74→      options: needsOptions
    75→        ? optionsText.split('\n').filter((opt) => opt.trim()).map((opt) => opt.trim())
    76→        : undefined,
    77→    };
    78→
    79→    onSave(finalField);
    80→  };
    81→
    82→  return (
    83→    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
    84→      <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg max-w-2xl w-full max-h-[90vh] overflow-y-auto">
    85→        {/* Header */}
    86→        <div className="flex items-center justify-between p-4 border-b border-border-light dark:border-border-dark sticky top-0 bg-surface-light dark:bg-surface-dark">
    87→          <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
    88→            {field ? 'Edit Field' : 'Add Field'}
    89→          </h2>
    90→          <button
    91→            onClick={onCancel}
    92→            className="p-2 hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark rounded"
    93→            aria-label="Close"
    94→          >
    95→            <X className="w-5 h-5" />
    96→          </button>
    97→        </div>
    98→
    99→        {/* Form */}
   100→        <form onSubmit={handleSubmit} className="p-4 space-y-4">
   101→          {/* Field Type */}
   102→          <div>
   103→            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   104→              Field Type *
   105→            </label>
   106→            <select
   107→              value={formData.type}
   108→              onChange={(e) => setFormData({ ...formData, type: e.target.value as FieldType })}
   109→              className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
   110→            >
   111→              {FIELD_TYPES.map((type) => (
   112→                <option key={type.value} value={type.value}>
   113→                  {type.label}
   114→                </option>
   115→              ))}
   116→            </select>
   117→          </div>
   118→
   119→          {/* Label */}
   120→          <div>
   121→            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   122→              Label *
   123→            </label>
   124→            <input
   125→              type="text"
   126→              value={formData.label}
   127→              onChange={(e) => setFormData({ ...formData, label: e.target.value })}
   128→              placeholder="e.g., 'How many hours did you sleep?'"
   129→              className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
   130→              required
   131→            />
   132→          </div>
   133→
   134→          {/* Description */}
   135→          <div>
   136→            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   137→              Description (Optional)
   138→            </label>
   139→            <textarea
   140→              value={formData.description || ''}
   141→              onChange={(e) => setFormData({ ...formData, description: e.target.value })}
   142→              placeholder="Help text for this field"
   143→              rows={2}
   144→              className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
   145→            />
   146→          </div>
   147→
   148→          {/* Options (for select/radio/multiselect) */}
   149→          {needsOptions && (
   150→            <div>
   151→              <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   152→                Options (one per line) *
   153→              </label>
   154→              <textarea
   155→                value={optionsText}
   156→                onChange={(e) => setOptionsText(e.target.value)}
   157→                placeholder="Option 1&#10;Option 2&#10;Option 3"
   158→                rows={5}
   159→                className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark font-mono text-sm"
   160→                required
   161→              />
   162→            </div>
   163→          )}
   164→
   165→          {/* Validation (for number fields) */}
   166→          {formData.type === 'number' && (
   167→            <div className="grid grid-cols-2 gap-4">
   168→              <div>
   169→                <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   170→                  Min Value (Optional)
   171→                </label>
   172→                <input
   173→                  type="number"
   174→                  value={formData.validation?.min ?? ''}
   175→                  onChange={(e) =>
   176→                    setFormData({
   177→                      ...formData,
   178→                      validation: {
   179→                        ...formData.validation,
   180→                        min: e.target.value ? Number(e.target.value) : undefined,
   181→                      },
   182→                    })
   183→                  }
   184→                  className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
   185→                />
   186→              </div>
   187→              <div>
   188→                <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   189→                  Max Value (Optional)
   190→                </label>
   191→                <input
   192→                  type="number"
   193→                  value={formData.validation?.max ?? ''}
   194→                  onChange={(e) =>
   195→                    setFormData({
   196→                      ...formData,
   197→                      validation: {
   198→                        ...formData.validation,
   199→                        max: e.target.value ? Number(e.target.value) : undefined,
   200→                      },
   201→                    })
   202→                  }
   203→                  className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
   204→                />
   205→              </div>
   206→            </div>
   207→          )}
   208→
   209→          {/* File Upload Configuration */}
   210→          {formData.type === 'file' && (
   211→            <div className="space-y-4 p-4 border border-border-light dark:border-border-dark rounded-lg bg-surface-light-elevated dark:bg-surface-dark-elevated">
   212→              <h4 className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
   213→                File Upload Settings
   214→              </h4>
   215→
   216→              {/* Max File Size */}
   217→              <div>
   218→                <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   219→                  Max File Size (MB)
   220→                </label>
   221→                <input
   222→                  type="number"
   223→                  value={formData.fileConfig?.maxSizeMB ?? 10}
   224→                  onChange={(e) =>
   225→                    setFormData({
   226→                      ...formData,
   227→                      fileConfig: {
   228→                        ...formData.fileConfig,
   229→                        maxSizeMB: Number(e.target.value) || 10,
   230→                        allowedTypes: formData.fileConfig?.allowedTypes || ['image/*', 'application/pdf'],
   231→                        multiple: formData.fileConfig?.multiple ?? false,
   232→                      },
   233→                    })
   234→                  }
   235→                  min={1}
   236→                  max={50}
   237→                  className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
   238→                />
   239→              </div>
   240→
   241→              {/* Allowed File Types */}
   242→              <div>
   243→                <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   244→                  Allowed File Types
   245→                </label>
   246→                <div className="space-y-2">
   247→                  {['image/*', 'application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document', 'text/plain'].map((type) => (
   248→                    <label key={type} className="flex items-center gap-2">
   249→                      <input
   250→                        type="checkbox"
   251→                        checked={formData.fileConfig?.allowedTypes?.includes(type) ?? (type === 'image/*' || type === 'application/pdf')}
   252→                        onChange={(e) => {
   253→                          const currentTypes = formData.fileConfig?.allowedTypes || ['image/*', 'application/pdf'];
   254→                          const newTypes = e.target.checked
   255→                            ? [...currentTypes, type]
   256→                            : currentTypes.filter((t) => t !== type);
   257→
   258→                          setFormData({
   259→                            ...formData,
   260→                            fileConfig: {
   261→                              maxSizeMB: formData.fileConfig?.maxSizeMB ?? 10,
   262→                              allowedTypes: newTypes,
   263→                              multiple: formData.fileConfig?.multiple ?? false,
   264→                            },
   265→                          });
   266→                        }}
   267→                        className="w-4 h-4"
   268→                      />
   269→                      <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
   270→                        {type === 'image/*' ? 'Images (PNG, JPG, GIF, etc.)' :
   271→                         type === 'application/pdf' ? 'PDF' :
   272→                         type === 'application/msword' ? 'Word (.doc)' :
   273→                         type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' ? 'Word (.docx)' :
   274→                         type === 'text/plain' ? 'Text files' : type}
   275→                      </span>
   276→                    </label>
   277→                  ))}
   278→                </div>
   279→              </div>
   280→
   281→              {/* Multiple Files Toggle */}
   282→              <div className="flex items-center gap-2">
   283→                <input
   284→                  type="checkbox"
   285→                  id="multiple-files"
   286→                  checked={formData.fileConfig?.multiple ?? false}
   287→                  onChange={(e) =>
   288→                    setFormData({
   289→                      ...formData,
   290→                      fileConfig: {
   291→                        maxSizeMB: formData.fileConfig?.maxSizeMB ?? 10,
   292→                        allowedTypes: formData.fileConfig?.allowedTypes || ['image/*', 'application/pdf'],
   293→                        multiple: e.target.checked,
   294→                      },
   295→                    })
   296→                  }
   297→                  className="w-4 h-4"
   298→                />
   299→                <label htmlFor="multiple-files" className="text-sm text-text-light-primary dark:text-text-dark-primary">
   300→                  Allow multiple files
   301→                </label>
   302→              </div>
   303→            </div>
   304→          )}
   305→
   306→          {/* Required Toggle */}
