   308→            <input
   309→              type="checkbox"
   310→              id="required"
   311→              checked={formData.required}
   312→              onChange={(e) => setFormData({ ...formData, required: e.target.checked })}
   313→              className="w-4 h-4"
   314→            />
   315→            <label htmlFor="required" className="text-sm text-text-light-primary dark:text-text-dark-primary">
   316→              Required field
   317→            </label>
   318→          </div>
   319→
   320→          {/* Advanced Options Toggle */}
   321→          <div className="border-t border-border-light dark:border-border-dark pt-4">
   322→            <button
   323→              type="button"
   324→              onClick={() => setShowAdvancedOptions(!showAdvancedOptions)}
   325→              className="flex items-center gap-2 text-sm font-medium text-primary-light dark:text-primary-dark hover:underline"
   326→            >
   327→              {showAdvancedOptions ? '▼' : '▶'} Advanced Options
   328→            </button>
   329→          </div>
   330→
   331→          {/* Advanced Options */}
   332→          {showAdvancedOptions && (
   333→            <div className="space-y-4 p-4 border border-border-light dark:border-border-dark rounded-lg bg-surface-light-elevated dark:bg-surface-dark-elevated">
   334→              {/* Conditional Logic */}
   335→              <ConditionalRuleEditor
   336→                field={formData}
   337→                allFields={allFields}
   338→                onRulesChange={(rules) =>
   339→                  setFormData({ ...formData, conditionalRules: rules })
   340→                }
   341→              />
   342→            </div>
   343→          )}
   344→
   345→          {/* Actions */}
   346→          <div className="flex justify-end gap-2 pt-4">
   347→            <button
   348→              type="button"
   349→              onClick={onCancel}
   350→              className="px-4 py-2 bg-surface-hover-light dark:bg-surface-hover-dark rounded-lg hover:bg-border-light dark:hover:bg-border-dark"
   351→            >
   352→              Cancel
   353→            </button>
   354→            <button
   355→              type="submit"
