     1→/**
     2→ * Formula Field Editor Component
     3→ *
     4→ * Configuration UI for formula fields with expression builder and field reference autocomplete.
     5→ * Shows live preview of computed value.
     6→ */
     7→
     8→import { useState, useRef, useEffect } from 'react';
     9→import { Calculator, AlertCircle, CheckCircle } from 'lucide-react';
    10→import type { FieldDefinition } from '../../types/customFields';
    11→import { evaluateFormula, extractFieldReferences, detectCircularReferences } from '../../utils/formulaEngine';
    12→
    13→interface FormulaFieldEditorProps {
    14→  expression: string;
    15→  onExpressionChange: (expression: string) => void;
    16→  allFields: FieldDefinition[];
    17→  currentFieldId?: string;
    18→  previewValues?: Record<string, any>;
    19→  className?: string;
    20→}
    21→
    22→export function FormulaFieldEditor({
    23→  expression,
    24→  onExpressionChange,
    25→  allFields,
    26→  currentFieldId,
    27→  previewValues = {},
    28→  className = '',
    29→}: FormulaFieldEditorProps) {
    30→  const [localExpression, setLocalExpression] = useState(expression);
    31→  const [showFieldPicker, setShowFieldPicker] = useState(false);
    32→  const [cursorPosition, setCursorPosition] = useState(0);
    33→  const textareaRef = useRef<HTMLTextAreaElement>(null);
    34→  const fieldPickerRef = useRef<HTMLDivElement>(null);
    35→
    36→  // Extract referenced fields
    37→  const referencedFields = extractFieldReferences(localExpression);
    38→
    39→  // Detect circular references
    40→  const hasCircularRef = currentFieldId
    41→    ? detectCircularReferences(
    42→        currentFieldId,
    43→        referencedFields,
    44→        allFields.map((f) => ({ id: f.id, referencedFields: f.referencedFields }))
    45→      )
    46→    : false;
    47→
    48→  // Evaluate formula for preview
    49→  const evaluation = evaluateFormula(localExpression, previewValues);
    50→
    51→  // Close field picker when clicking outside
    52→  useEffect(() => {
    53→    function handleClickOutside(event: MouseEvent) {
    54→      if (
    55→        fieldPickerRef.current &&
    56→        !fieldPickerRef.current.contains(event.target as Node) &&
    57→        textareaRef.current &&
    58→        !textareaRef.current.contains(event.target as Node)
    59→      ) {
    60→        setShowFieldPicker(false);
    61→      }
    62→    }
    63→
    64→    if (showFieldPicker) {
    65→      document.addEventListener('mousedown', handleClickOutside);
    66→      return () => document.removeEventListener('mousedown', handleClickOutside);
    67→    }
    68→  }, [showFieldPicker]);
    69→
    70→  const handleExpressionChange = (newExpression: string) => {
    71→    setLocalExpression(newExpression);
    72→    onExpressionChange(newExpression);
    73→  };
    74→
    75→  const handleInsertField = (field: FieldDefinition) => {
    76→    const before = localExpression.slice(0, cursorPosition);
    77→    const after = localExpression.slice(cursorPosition);
    78→    const fieldRef = `{${field.id}}`;
    79→    const newExpression = before + fieldRef + after;
    80→
    81→    handleExpressionChange(newExpression);
    82→    setShowFieldPicker(false);
    83→
    84→    // Move cursor after inserted field
    85→    setTimeout(() => {
    86→      if (textareaRef.current) {
    87→        const newPos = cursorPosition + fieldRef.length;
    88→        textareaRef.current.focus();
    89→        textareaRef.current.setSelectionRange(newPos, newPos);
    90→      }
    91→    }, 0);
    92→  };
    93→
    94→  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    95→    if (e.key === '{') {
    96→      // Show field picker when typing '{'
    97→      setCursorPosition(e.currentTarget.selectionStart + 1);
    98→      setShowFieldPicker(true);
    99→    } else if (e.key === 'Escape') {
   100→      setShowFieldPicker(false);
   101→    }
   102→  };
   103→
   104→  // Filter fields that can be referenced (exclude formula fields that would create circular refs)
   105→  const availableFields = allFields.filter((f) => {
   106→    // Exclude current field
   107→    if (currentFieldId && f.id === currentFieldId) return false;
   108→
   109→    // Exclude formula fields for now (to prevent complex circular reference chains)
   110→    if (f.type === 'formula') return false;
   111→
   112→    return true;
   113→  });
   114→
   115→  return (
   116→    <div className={className}>
   117→      {/* Formula Expression Input */}
   118→      <div className="relative">
   119→        <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
   120→          Formula Expression
   121→        </label>
   122→
   123→        <textarea
   124→          ref={textareaRef}
   125→          value={localExpression}
   126→          onChange={(e) => handleExpressionChange(e.target.value)}
   127→          onKeyDown={handleKeyDown}
   128→          onClick={(e) => setCursorPosition(e.currentTarget.selectionStart)}
   129→          placeholder="e.g., {field1} + {field2} * 2 or IF({status} = 'Done', 100, 0)"
   130→          rows={4}
   131→          className="w-full px-3 py-2 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary font-mono text-sm focus:outline-none focus:ring-2 focus:ring-accent-blue"
   132→          aria-label="Formula expression"
   133→        />
   134→
   135→        {/* Field Picker Dropdown */}
   136→        {showFieldPicker && (
   137→          <div
   138→            ref={fieldPickerRef}
   139→            className="absolute z-10 w-full mt-1 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg shadow-lg max-h-60 overflow-y-auto"
   140→          >
   141→            {availableFields.length > 0 ? (
   142→              <ul className="py-1">
   143→                {availableFields.map((field) => (
   144→                  <li key={field.id}>
   145→                    <button
   146→                      onClick={() => handleInsertField(field)}
   147→                      className="w-full px-3 py-2 text-left hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark text-text-light-primary dark:text-text-dark-primary"
   148→                    >
   149→                      <div className="font-medium">{field.name}</div>
   150→                      <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   151→                        {field.type} field
   152→                      </div>
   153→                    </button>
   154→                  </li>
   155→                ))}
   156→              </ul>
   157→            ) : (
   158→              <div className="px-3 py-4 text-center text-text-light-secondary dark:text-text-dark-secondary text-sm">
   159→                No fields available to reference
   160→              </div>
   161→            )}
   162→          </div>
   163→        )}
   164→      </div>
   165→
   166→      {/* Helper Text */}
   167→      <div className="mt-2 text-xs text-text-light-secondary dark:text-text-dark-secondary space-y-1">
   168→        <p>Type <code className="px-1 py-0.5 bg-surface-hover-light dark:bg-surface-hover-dark rounded">{'{'}</code> to insert a field reference</p>
   169→        <p>Supported: +, -, *, /, IF(), SUM(), AVERAGE(), COUNT(), DAYS_BETWEEN()</p>
   170→      </div>
   171→
   172→      {/* Circular Reference Warning */}
   173→      {hasCircularRef && (
   174→        <div className="mt-3 p-3 bg-status-error/10 dark:bg-status-error/20 border border-status-error rounded-lg flex items-start gap-2">
   175→          <AlertCircle className="w-4 h-4 text-status-error-text dark:text-status-error-text-dark shrink-0 mt-0.5" />
   176→          <div className="text-sm text-status-error-text dark:text-status-error-text-dark">
   177→            <strong>Circular Reference Detected:</strong> This formula references fields that create a circular dependency.
   178→          </div>
   179→        </div>
   180→      )}
   181→
   182→      {/* Preview */}
   183→      {!hasCircularRef && localExpression && (
   184→        <div className="mt-3 p-3 bg-surface-hover-light dark:bg-surface-hover-dark rounded-lg border border-border-light dark:border-border-dark">
   185→          <div className="flex items-center gap-2 mb-2">
   186→            <Calculator className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
   187→            <span className="text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary uppercase">
   188→              Preview
   189→            </span>
   190→          </div>
   191→
   192→          {evaluation.error ? (
   193→            <div className="flex items-start gap-2">
   194→              <AlertCircle className="w-4 h-4 text-status-error-text dark:text-status-error-text-dark shrink-0 mt-0.5" />
   195→              <div className="text-sm text-status-error-text dark:text-status-error-text-dark">
   196→                {evaluation.error}
   197→              </div>
   198→            </div>
   199→          ) : (
   200→            <div className="flex items-start gap-2">
   201→              <CheckCircle className="w-4 h-4 text-accent-green shrink-0 mt-0.5" />
   202→              <div>
   203→                <div className="text-sm text-text-light-primary dark:text-text-dark-primary font-medium">
   204→                  {formatPreviewValue(evaluation.value)}
   205→                </div>
   206→                <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
   207→                  Result type: {typeof evaluation.value}
   208→                </div>
   209→              </div>
   210→            </div>
   211→          )}
   212→        </div>
   213→      )}
   214→
   215→      {/* Referenced Fields */}
   216→      {referencedFields.length > 0 && (
   217→        <div className="mt-3">
   218→          <div className="text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
   219→            Referenced Fields:
   220→          </div>
   221→          <div className="flex flex-wrap gap-1">
   222→            {referencedFields.map((fieldId) => {
   223→              const field = allFields.find((f) => f.id === fieldId);
   224→              return (
   225→                <span
   226→                  key={fieldId}
   227→                  className="inline-flex items-center px-2 py-0.5 bg-accent-blue/10 dark:bg-accent-blue/20 text-accent-blue dark:text-accent-blue-hover rounded text-xs"
   228→                >
   229→                  {field ? field.name : `Unknown (${fieldId})`}
   230→                </span>
   231→              );
   232→            })}
   233→          </div>
   234→        </div>
   235→      )}
   236→    </div>
   237→  );
   238→}
   239→
   240→/**
   241→ * Format preview value for display
