   222→            {field.type === 'time' && <TimeField {...fieldProps} />}
   223→            {field.type === 'select' && <SelectField {...fieldProps} />}
   224→            {field.type === 'multiselect' && <MultiSelectField {...fieldProps} />}
   225→            {field.type === 'radio' && <RadioField {...fieldProps} />}
   226→            {field.type === 'checkbox' && <CheckboxField {...fieldProps} />}
   227→            {field.type === 'rating' && <RatingField {...fieldProps} />}
   228→            {field.type === 'scale' && <ScaleField {...fieldProps} />}
   229→            {field.type === 'file' && <FileUploadField {...fieldProps} />}
   230→          </div>
   231→        );
   232→      })}
   233→
   234→      {/* Honeypot Field (hidden from humans, visible to bots) */}
