   236→        <div className="absolute left-[-9999px]" aria-hidden="true">
   237→          <label htmlFor="email_confirm">Email Confirmation</label>
   238→          <input
   239→            type="text"
   240→            id="email_confirm"
   241→            name="email_confirm"
   242→            value={honeypot}
   243→            onChange={(e) => setHoneypot(e.target.value)}
   244→            tabIndex={-1}
   245→            autoComplete="off"
   246→          />
   247→        </div>
   248→      )}
   249→
   250→      <div className="flex justify-end pt-4">
   251→        <button
   252→          type="submit"
   253→          className="px-6 py-3 bg-primary-light dark:bg-primary-dark text-white rounded-lg hover:opacity-90 transition-opacity font-medium"
   254→        >
