   256→        </button>
   257→      </div>
   258→    </form>
   259→  );
   260→}
   261→
   262→/**
   263→ * Evaluate a single conditional rule
   264→ * Returns true if the rule evaluates to "show", false if "hide" or condition not met
   265→ */
   266→function evaluateConditionalRule(
   267→  rule: ConditionalRule,
   268→  answers: Record<string, any>
   269→): boolean {
   270→  const triggerValue = answers[rule.fieldId];
   271→
   272→  // Evaluate the condition based on operator
   273→  let conditionMet = false;
   274→
   275→  switch (rule.operator) {
   276→    case 'is_answered':
   277→      conditionMet = triggerValue !== undefined && triggerValue !== null && triggerValue !== '';
   278→      break;
   279→
   280→    case 'is_not_answered':
   281→      conditionMet = triggerValue === undefined || triggerValue === null || triggerValue === '';
   282→      break;
   283→
   284→    case 'equals':
   285→      // Handle array values (multiselect)
   286→      if (Array.isArray(triggerValue)) {
   287→        conditionMet = triggerValue.includes(rule.value);
   288→      } else {
   289→        conditionMet = String(triggerValue) === String(rule.value);
   290→      }
   291→      break;
   292→
   293→    case 'not_equals':
   294→      // Handle array values (multiselect)
   295→      if (Array.isArray(triggerValue)) {
   296→        conditionMet = !triggerValue.includes(rule.value);
   297→      } else {
   298→        conditionMet = String(triggerValue) !== String(rule.value);
   299→      }
   300→      break;
   301→
   302→    case 'contains':
   303→      if (typeof triggerValue === 'string') {
   304→        conditionMet = triggerValue.toLowerCase().includes(String(rule.value).toLowerCase());
   305→      } else if (Array.isArray(triggerValue)) {
   306→        conditionMet = triggerValue.some((v) =>
   307→          String(v).toLowerCase().includes(String(rule.value).toLowerCase())
   308→        );
   309→      }
   310→      break;
   311→
   312→    default:
   313→      conditionMet = false;
   314→  }
   315→
   316→  // Return based on action (show or hide)
   317→  // If action is 'show' and condition is met → return true (show the field)
   318→  // If action is 'hide' and condition is met → return false (hide the field)
   319→  // If action is 'show' and condition is NOT met → return false (don't show)
   320→  // If action is 'hide' and condition is NOT met → return true (don't hide)
   321→  return rule.action === 'show' ? conditionMet : !conditionMet;
   322→}
   323→

