                        {triggerField?.type === 'select' || triggerField?.type === 'radio' ? (
                          <select
                            value={validation.condition.value || ''}
                            onChange={(e) =>
                              handleUpdateValidation(index, {
                                condition: { ...validation.condition, value: e.target.value },
                              })
                            }
                            className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg bg-background-light dark:bg-background-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-cyan"
                          >
                            <option value="">Select an option...</option>
                            {triggerField.options?.map((option) => (
                              <option key={option} value={option}>
                                {option}
                              </option>
                            ))}
                          </select>
                        ) : (
                          <input
                            type="text"
                            value={validation.condition.value || ''}
                            onChange={(e) =>
                              handleUpdateValidation(index, {
                                condition: { ...validation.condition, value: e.target.value },
                              })
                            }
                            placeholder="Enter value..."
                            className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg bg-background-light dark:bg-background-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-cyan"
                          />
