                      </div>
                    )}
                  </div>
                </div>

                {/* Validation Rule */}
                <div className="space-y-3">
                  {/* Validation Value (for min/max/pattern) */}
                  {needsValidationValue && (
                    <div>
                      <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
