                      }
                      className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg bg-surface-light-base dark:bg-surface-dark-base text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-magenta"
                    >
                      <option value="equals">Equals</option>
                      <option value="not_equals">Not Equals</option>
                      <option value="contains">Contains</option>
                      <option value="is_answered">Is Answered</option>
                      <option value="is_not_answered">Is Not Answered</option>
                    </select>
                  </div>

                  {/* Value input (if needed) */}
                  {needsValue && (
                    <div className="md:col-span-2">
                      <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
                        Value
                      </label>
                      {triggerField?.type === 'select' || triggerField?.type === 'radio' ? (
                        // Dropdown for select/radio fields
                        <select
                          value={rule.value || ''}
                          onChange={(e) => handleUpdateRule(index, { value: e.target.value })}
                          className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg bg-surface-light-base dark:bg-surface-dark-base text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-magenta"
                        >
                          <option value="">Select an option...</option>
                          {triggerField.options?.map((option) => (
                            <option key={option} value={option}>
                              {option}
                            </option>
