  switch (operator) {
    case 'equals':
      return 'equals';
    case 'not_equals':
      return 'does not equal';
    case 'contains':
      return 'contains';
    case 'is_answered':
      return 'is answered';
    case 'is_not_answered':
      return 'is not answered';
    default:
      return operator;
  }
}

